var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"역시……. 나무에서 떨어질 때 탐지 기능이 완전히 망가져 버렸어.","JPN":"やはり……木から落ちた時に探知機能が完全に壊れてしまった。","ENG":"I knew it... The detector must've broke when I fell off the tree.","TWN":"果然… 從樹上摔下來時，探測功能完全毀了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"곤란하네. 이런 외진 곳에서 수리에 쓸 부품을 구할 수도 없고.","JPN":"まいったな。こんな人里離れた場所では修理に使える部品も手に入らないし。","ENG":"This isn't good. Where am I going to find replacement parts out here?","TWN":"真傷腦筋，在這麼偏僻的地方又買不到零件來修理。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"후우….","JPN":"ふう……","ENG":"*Sigh...*","TWN":"哀哀…"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"고민이 있는 한숨소리군요.","JPN":"悩み事があるような溜息ですね。","ENG":"That's sounds like a worried sigh.","TWN":"是煩惱的嘆氣聲。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"누가 마음대로 들어와도 된다고 했지?","JPN":"誰が勝手に入っていいと言った？","ENG":"Who gave you permission to come in here?","TWN":"誰說你可以進來的？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"셔우드 외성에 제대로 된 정비소는 여기 한 곳밖에 없어서 말이죠.","JPN":"シャーウッド外郭でまともな整備工場はここしかありませんので。","ENG":"This is the only maintenance station in this village.","TWN":"因為休烏特外城只有一家像樣的維修站。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이 친구를 잠시 점검하려고 들렀습니다.","JPN":"こいつを少々点検するために来ました。","ENG":"I came to check up on my friend over here.","TWN":"我是來看看這小子的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORSE_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"……그 때 우리를 태워 준 병기마로군.","JPN":"……あの時私たちを乗せてくれた兵器馬だな。","ENG":"That's the Armored Horse that I rode on...","TWN":"……是上次載我們的戰馬。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HORSE_BORDER_NULL_NAMED","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORSE_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_STEAM"},{"id":"L30_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"으앗?!","JPN":"わあっ！？","ENG":"Wah?!","TWN":"哇啊？！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"바, 방금 그건 뭐야! 공격하려는 건가?!","JPN":"い、今のは何だ！　攻撃しようとしたのか！？","ENG":"W-what was that?! Is it going to attack me?!","TWN":"剛…剛才那是怎樣！是要攻擊我嗎？！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"놀라게 해드렸다면 죄송합니다.","JPN":"驚かせて申し訳ありません。","ENG":"I apologize if Hermit scared you.","TWN":"抱歉，嚇到你。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"동력부가 만드는 출력으로 과부하에 걸려서, 주기적으로 에너지를 방출하게 해 뒀습니다.","JPN":"動力部が作る出力で負荷がかかりすぎるので、周期的にエネルギーを放出するようにしてあります。","ENG":"The generator output is too much for him, so I made some adjustments so that he periodically emits excess energy.","TWN":"由於動能部產生的輸出超出負荷，所以會定時釋放能量。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"흥…….","JPN":"フン……","ENG":"Hmph...","TWN":"哼……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"병기마는 왕실 최고 기술자만이 그 주인을 결정할 권한이 있다.","JPN":"兵器馬は王室の最高技術者のみがその主人を決める権限を持つ。","ENG":"Only the Royal Chief Technician have the authority to bestow an Armored Horses to someone.","TWN":"只有皇室頂尖技師才有權決定戰馬的主人。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"한낱 수비대의 지휘참모가 어떻게 병기마를 부리는 거지?","JPN":"単なる守備隊の指揮参謀がどうして兵器馬を使っているんだ？","ENG":"How come an ordinary soldier like you is able to have one?","TWN":"區區一個護衛隊的指揮官怎麼可以控制戰馬呢？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"오래 전부터 저와 함께한 친구입니다.","JPN":"昔から共に歩んできた友なのです。","ENG":"He and I are old friends.","TWN":"我們已經相識許久，"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"비록 저는 기억을 잃었습니다만, 이 친구는 다행히 저를 잊지 않고 따라 주더군요.","JPN":"私は記憶を失いましたが、この友は幸い私を忘れずについてきてくれました。","ENG":"Thankfully enough, even though I've lost my memories, he hasn't forgotten who I am.","TWN":"雖然我現在失去記憶，但幸好它沒有遺忘我，一直跟著我。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"웃기는군. 그러면 네 놈이 전멸한 총사대의 생존자라도 된다는 거냐?","JPN":"笑わせる。だとしたら、貴様が全滅した銃士隊の生き残りだとでもいうのか？","ENG":"Don't make me laugh. Are you saying that you're a survivor of the annihilated Musketeer Division or something?","TWN":"笑死人，意思是你是全軍覆沒射擊隊中的倖存者嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"제라드 큐리안.","JPN":"ジェラード・キュリアン。","ENG":"Gerard Curian.","TWN":"傑瑞德· 庫里安。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그게 제가 기억하는 이름입니다.","JPN":"それが私が覚えている名前です。","ENG":"That's the name I remember.","TWN":"這是我記得的名字。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"……총사대장 큐리안?","JPN":"……銃士隊長キュリアン？","ENG":"General Musketeer Curian?","TWN":"……隊長庫里安？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"어이가 없군. 감히 왕실 장교 앞에서 국가지명수배자의 이름을 들먹여?","JPN":"呆れたな。王室将校の前で国家指名手配者の名を口にするのか？","ENG":"Don't be ridiculous. How dare you say that traitor's name in front of a Royal officer?","TWN":"真是無言，竟敢在皇室軍官的面前提起國家通緝犯的名字？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"방금 그 대답으로 내가 널 즉결 처단해도 아무 문제 없게 됐어. 알고는 있나?","JPN":"今のその答えで貴様を即処断してもなんの問題もなくなったんだぞ。わかっているのか？","ENG":"Did you know that answer alone is enough for me to execute you?","TWN":"你知道嗎？光是你剛才的回話，我就可以當場處決你。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"언젠가 밝혀질 사실이었고, 처벌은 두렵지 않습니다.","JPN":"いつかは明らかになる事実でしたし、処罰は怖くありません。","ENG":"The truth will one day be revealed. And I do not fear the punishment.","TWN":"總有一天會真相大白的，我不怕刑罰。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"다만 처벌을 받기 전에 열쇠를 찾는 일을 돕게 해 주십시오.","JPN":"ただ、処罰される前に鍵を探すことを手伝わせてください。","ENG":"Nonetheless, please let me help you find the Key before it comes to that.","TWN":"只是在接受刑罰前，請允許我一起找鑰匙。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"열쇠의 마지막 행방을 아는 건 큐리안과 그 부대원들뿐이야! 지금 날 우롱하는 건가!","JPN":"鍵の最後の行方を知っているのはキュリアンとその部隊員だけだ！　私を愚弄しているのか！","ENG":"Only Curian and his men know about the Key's last whereabouts! Are you mocking me right now!?","TWN":"只有庫里安和他的隊員才知道鑰匙的下落！你現在是在耍我嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…모릅니다.","JPN":"……わかりません。","ENG":"I don't know where it is.","TWN":"…我不知道。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"저에게 남은 건 수도를 떠나 남부로 향하던 기억의 단편뿐.","JPN":"私に残っているのは首都を発ち、南部に向かっていた記憶の断片のみです。","ENG":"I can only recall fragments of heading south from the capital.","TWN":"我的記憶只剩下離開首都前往南方的片段。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"열쇠가 어떻게 사라졌는지, 20년 사이에 무슨 일이 있었는지 모두 잊어 버렸으니까요.","JPN":"鍵がどうやって消えたのか、20年の間どんなことが起きたのかすべて忘れてしまいましたから。","ENG":"I have no memories of where the Key was lost or what happened in the past 20 years.","TWN":"鑰匙是怎麼消失的，這20年來發生什麼事，我都不記得。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"……침식파가 인간에게 미치는 영향은 아주 다양하지.","JPN":"……侵食波が人間に及ぼす影響は様々だ。","ENG":"...The Corruption ray affects people in various ways.","TWN":"……侵蝕波對人類的影響是很多樣的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"환각을 경험하고 악몽에 시달리는가 하면, 자신이 누군지 잊어 버리기도 한다.","JPN":"幻覚を経験して悪夢に苦しんだり、自分が何者なのか忘れたりもする。","ENG":"Some experience hallucinations and nightmares, and some even forget who they are.","TWN":"產生幻覺，受惡夢折磨，也會忘記自己是誰。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"아무래도 넌 그런 부류의 망상증에 시달리는 것 같군. 진지하게 반응한 내가 어리석었지.","JPN":"どうやら貴様はそういった部類の妄想障害に悩まされているようだな。真面目に反応した私が愚かだった。","ENG":"It seems that you fall into the delusion category. I'm sorry for lashing out at you like that.","TWN":"看來你的症狀是有妄想症，我在跟你認真什麼，真是愚蠢。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"오늘 나와 한나 씨를 구해 준 대가로, 방금 한 얘기는 못 들은 걸로 하겠다.","JPN":"今日私とハンナさんを救ってくれた礼として、今の話は聞かなかったことにしてやる。","ENG":"I'll pretend I didn't hear what you just said in return for saving me and Hanna today.","TWN":"就當作是你今天救我和漢娜的回報，剛才你說的話，我就當沒聽見。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그런 헛소리는 두 번 다시 어디 가서 내뱉지 말도록. 이게 내 마지막 관용이다.","JPN":"二度とそういうでたらめを口にするな。許すのはこれが最後だ。","ENG":"A word of advice, don't ever say that in front of anyone again.","TWN":"不要再胡說八道，這是我最後一次容忍你。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"새겨듣겠습니다.","JPN":"肝に銘じておきます。","ENG":"I'll keep that in mind.","TWN":"我會銘記在心的"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그런데 물건을 수리 중이시던 겁니까?","JPN":"ところで、何か修理されていたのですか？","ENG":"By the way, were you trying to fix something?","TWN":"不過，你在修理東西嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그건 네가 알 바 아니…","JPN":"それは貴様とは関係がな……","ENG":"That's none of your busi─","TWN":"不關你的事…"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"뭣! 뭘 멋대로 건드는 거냐! 민감한 물건이란 말이다!","JPN":"なっ！　何を勝手に触ってるんだ！　敏感な物なんだ！","ENG":"Huh?! Don't touch that! It's sensitive equipment!","TWN":"幹嘛啦！你不要亂碰！這的東西很敏感的！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"파형 측정기를 소형화시킨 장치 같군요. 센서와 회로 일부가 파손됐어요.","JPN":"波形の測定器を小型にした装置のようですね。センサーと一部の回路が壊れています。","ENG":"Looks like a scaled-down version of the ray analyzer. But some of the sensors and wires are destroyed.","TWN":"似乎是縮小波形測量器的裝置，感應器和部分電路毀損。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"당장 내려놓지 못해! 그건 내……!","JPN":"今すぐそれを下ろせ！　それは私の……！","ENG":"Give that back! It's a me─!","TWN":"還不給我鬆手！那是我……！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"따라오시죠. 대체할 부품을 구할 만한 장소가 있습니다.","JPN":"ついてきてください。代わりとなる部品が手に入りそうな場所があります。","ENG":"Follow me. I know a place where we might find some replacement parts.","TWN":"跟我來吧，我知道有個地方可以找到代換得零件。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"……뭐?","JPN":"……何だと？","ENG":"What...?","TWN":"……什麼？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"차원함선이잖아……?","JPN":"次元艦船じゃないか……？","ENG":"That's a dimensional ship…?","TWN":"這不是次元艦船嗎……？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"대체 이런 게 왜 침식지대 한복판에 버려져 있는 거지?","JPN":"いったいなぜこんなものが侵食地帯のど真ん中に捨てられているんだ？","ENG":"What's that doing in the middle of a Corrupted Area?","TWN":"為什麼會被擱置在侵蝕地帶的正中央？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"1년 전쯤 마을 아이들이 찾아냈습니다. 여기 있는 이유는 저희도 아직 모릅니다.","JPN":"1年ほど前に村の子供たちが発見しました。なぜここにあるのかはまだ私たちにもわかりません。","ENG":"The village children discovered it about a year ago. We don't know why it's here either.","TWN":"大約一年前，村裡的孩子們找到的，我們也不知道爲什麼它會在這裡。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이런 귀중한 정보를 재건단에 알리지 않은 건 괘씸하다만…….","JPN":"こういう貴重な情報を再建団に知らせなかったのはけしからんが……","ENG":"I'm appalled that you didn't mention this useful information to the Alliance, but...","TWN":"可惡，竟然沒將這麼重要的情報告訴重建委員會…… "},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"너희 같은 무지렁이들은 차원함선의 가치를 몰랐을 테니, 이번만큼은 넘어가 주겠어.","JPN":"貴様らのような無学な者には次元艦船の価値がわからなかっただろうから、今度だけは大目に見てやろう。","ENG":"I'll forgive you since incompetents like you couldn't possibly have known the value of a dimensional ship.","TWN":"像你們這種土包子，怎麼可能知道次元艦船的價值，這次就不跟你們計較！"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그나저나 꼬마들이 제법 기특한 일을 해냈군. 지금 어디에 있지?","JPN":"それよりその子らはなかなか殊勝なことをしたな。今はどこにいる？","ENG":"Even so, those kids did some excellent work. Where are they now?","TWN":"話說回來，那些小鬼做得很不錯，他們人呢？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그 아이들은 이제 없습니다.","JPN":"その子供たちはもういません。","ENG":"The children are gone now.","TWN":"那些孩子已經不在了。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"음? 도시로 이주한 건가?","JPN":"うむ？　都市に移住したのか？","ENG":"Hmm? Do you mean they moved back to the city?","TWN":"嗯？是搬到都市了嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"외성의 주민들은 대부분 침식 증후군 환자들입니다. 치료를 받아도 연명 정도에 그치죠.","JPN":"外郭の住民はほとんどが侵食症候群の患者です。治療を受けても少し長く生きられる程度に過ぎません。","ENG":"The majority of the villagers in Sherwood suffer from Corruption Syndrome. Even with treatment, it is only enough to keep them alive.","TWN":"外城的居民大多數是侵蝕症候群的患者，即使接受治療，也只是苟延殘喘而已。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"수비대장도 살리기 위해 노력했습니다만, 나이가 어리다고 예외는 아니더군요.","JPN":"守備隊長も助けようと頑張りましたが、若いからといって例外とはならないのですね。","ENG":"Captain Ella tried her best to keep them alive but... the syndrome didn't care about that they were young.","TWN":"護衛隊長已經很努力要救活他們，只是並非年紀小就能脫離死亡的宿命。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그래도 도시에서 모르핀을 구할 수 있던 때라 마지막은 고통스럽지 않았을 겁니다.","JPN":"それでも都市からモルヒネを買うことができた時期ですので、最期は苦しくなかったはずです。","ENG":"We were, however, able to get some morphine from the city at the time. So their last moments should've been peaceful.","TWN":"不過那時候還能在城裡能買到嗎啡，他們生命的最後應該不會太痛苦。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…그런가.","JPN":"……そうか。","ENG":"…I see.","TWN":"…是嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"난 여기서 쓸 만한 부품을 찾아 봐야겠어.","JPN":"私はここで使えそうな部品を探してみる。","ENG":"I'm going see if I can find some useful parts.","TWN":"我要在這裡找找看有沒有能用的零件。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"저도 돕겠습니다.","JPN":"私も手伝いましょう。","ENG":"I'll help.","TWN":"我也幫忙找。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"좋을 대로 해.","JPN":"好きにしろ。","ENG":"Suit yourself.","TWN":"隨便你。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"쳇, 레이더는 전부 망가진 건가? 멀쩡한 부품이 하나도 없군.","JPN":"ちっ、レーダーは全部壊れているのか？　まともな部品がひとつもないな。","ENG":"Tch! The radar's completely ruined! There's not a single part I can use.","TWN":"嘖，雷達全都是壞的嗎？沒有一個零件是好的。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이건… 경보?","JPN":"これは……警報？","ENG":"Huh...? An alarm?","TWN":"這是… 警報聲？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"보안 시스템에 이상이 생긴 모양이군요. 제가 확인해보겠습니다.","JPN":"保安システムに問題が発生したようですね。私が確認してみます。","ENG":"Something must be tripping the security system. I'll go check it out.","TWN":"似乎安全系統出什麼問題的樣子，我確認一下。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"아니. 이건 함내에 침식파가 검출됐을 때 울리는 경보다.","JPN":"いや。これは艦内で侵食波が検出された時の警報だ。","ENG":"No, this is the alarm that goes off when it detects Corruption ray.","TWN":"不，這是艦船內檢測出侵蝕波時會有的警報聲。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이쪽으로 따라와.","JPN":"こっちに来い。","ENG":"Follow me. This way.","TWN":"跟我來。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"방금 지나간 녀석이 마지막인 것 같군.","JPN":"今通り過ぎたやつが最後のようだな。","ENG":"That looks like the last of them.","TWN":"剛才路過的傢伙好像是最後一個。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"저희가 있는 선실은 확인도 하지 않고 돌아갔습니다.","JPN":"私たちがいる船室は確認もせずに帰っていきました。","ENG":"They went back without checking our cabin.","TWN":"它們完全沒看我們所在的船艙一眼，"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"혹시 그 펜던트 덕분입니까?","JPN":"もしかしてそのペンダントのおかげなんですか？","ENG":"Is it because of that pendant?","TWN":"難道是因為那個掛飾的關係？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"맞아. 바로 눈치 채다니 제법이네.","JPN":"そうだ。すぐ気付くとは、なかなかだな。","ENG":"Yeah. You got a good eye.","TWN":"沒錯，竟然這麼快發現，有二下子喔。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"코앞에 있는 인간을 침식체가 그냥 지나칠 리 없으니까요. 유용한 물건이군요.","JPN":"すぐ近くに人間がいるのに、侵食体がそのまま通り過ぎるわけがないですから。役に立つ品物ですね。","ENG":"There's no way a C.O. wouldn't notice a person right in front of them. That's some nifty gear you got there.","TWN":"因為侵蝕體不會輕易放過眼前的人類，這東西不錯呢。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"}}}},{"id":"L14_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"놈들의 감각 기관에 혼선을 줄 뿐이야. 뻔히 보이는데도 따돌릴 수는 없어.","JPN":"やつらの感覚器官を混乱させるだけだ。丸見えではまくことはできない。","ENG":"It can only distract their sensory organs. They'll still come after us if we're out in plain sight.","TWN":"這只能混淆它們的感官，明明看得見，卻甩不掉。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그나마도 급이 높은 녀석들에게는 무용지물이지.","JPN":"それにランクが高いやつらには無用の長物だ。","ENG":"Also, it won't work against high-class C.O.s.","TWN":"而且這東西對高階侵蝕體是派不上用場的。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"재건단의 장교 분들은 모두 그런 장비를 지니고 있는 겁니까?","JPN":"再建団の将校は全員そういう装備を持っているんですか？","ENG":"Do all Alliance officers carry that equipment with them?","TWN":"重建委員會的軍官都會配置這樣的裝備嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"왜? 병사들이 차별받는 것 같아서 억울한가?","JPN":"何だ？　兵士が差別されてるようで悔しいのか？","ENG":"Why do you ask? You think it's unfair to the other soldiers?","TWN":"怎樣？因為士兵受到差別待遇而覺得委屈嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"아뇨. 이유는 짐작이 갑니다. 쉽게 양산할 수 없는 물건이라서겠죠.","JPN":"いいえ。理由は見当がつきます。簡単に量産できないものだからでしょう。","ENG":"No, I can sort of understand why. It must be because it can't be easily mass-produced.","TWN":"不是，原因大致可以猜到，應該是因為無法輕易量產吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그 말이 맞아. 값비싼 고순도 이터니움을 쓰는 데다 사용 가능한 횟수도 정해져 있거든.","JPN":"そのとおりだ。高価な高純度のエタニウムを使ってるし、使用できる回数も限られている。","ENG":"That's true. It requires expensive high-purity Eternium, and can only be used a limited number of times.","TWN":"你說得沒錯，不僅需要使用價格昂貴的高純度永恆之金，而且使用的次數也有限。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"아마 이것도… 앞으로 한 번쯤 더 쓰면 수명이 다하겠지.","JPN":"多分これも……もう一回使えばお終いだろう。","ENG":"Even this one... It looks like it only has one charge left.","TWN":"這個…可能再用一次，就要壽終正寢了。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그런 귀한 물건을 낭비하게 만들었군요. 죄송합니다.","JPN":"そのような貴重な品物を無駄遣いさせてしまいましたね。申し訳ありません。","ENG":"I apologize for wasting such a valuable asset on me.","TWN":"浪費那麼貴重的東西，真不好意思。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"착각 마라. 방금은 나를 위해 사용한 거야. 너는 내 옆에 우연히 있었을 뿐이지.","JPN":"勘違いするな。今は自分のために使ったんだ。貴様は偶然私のそばにいただけだ。","ENG":"Don't be mistaken. I used it on me. You just happened close enough.","TWN":"你別誤會，剛才是爲我自己用的，你只是剛好在我旁邊而已。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"크흠, 수리에 필요한 부품은 찾으셨습니까?","JPN":"こほん、修理に必要な部品は見つかりましたか？","ENG":"Ahem... So, what parts are you looking for again?","TWN":"咳咳，你有找到修理要用零件嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"늦었어. 대체품으로 쓸 수 있을 만한 레이더 장비는 모두 부서졌더군.","JPN":"手遅れだった。代わりに使えそうなレーダー装備はすべて壊れていた。","ENG":"Forget it. The radar's completely destroyed with no usable parts in it.","TWN":"沒有，能作為替代品的雷達設備沒一個是好的。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"그렇다면 이게 도움이 될지도 모릅니다.","JPN":"それならこれが役に立つかもしれません。","ENG":"Then maybe this will be of help.","TWN":"這樣的話，這或許會有幫助。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"그건…? 통신 모듈 아닌가?","JPN":"それは……？　通信モジュールではないか？","ENG":"Huh...? Isn't that a communication module?","TWN":"那個…？不是通訊模組嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이면세계를 횡단하는 함선이라면 통신기기에도 침식파에 대비해 뒀겠죠.","JPN":"裏世界を横断する艦船なら、通信機器も侵食波に備えていたはずです。","ENG":"If the ship was made to cross into Counterside, then this module should also be made to withstand the Corruption ray.","TWN":"若是穿越異界的艦船，那通訊機器應該也能防範侵蝕波吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"분해해 보면 쓸 만한 부품이 있을지도 모릅니다.","JPN":"分解してみれば、使える部品があるかもしれません。","ENG":"Perhaps there we can find some useful part if we disassemble it.","TWN":"拆開來看看吧，或許有可以用的零件。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"좋아. 밑져야 본전이니까.","JPN":"わかった。だめでもともとだからな。","ENG":"All right. It's worth a shot.","TWN":"好吧，試試也不吃虧。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…반응이 없군.","JPN":"……反応がない。","ENG":"It's not responding.","TWN":"…沒反應。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"역시 통신용과는 호환되지 않는 건가?","JPN":"やはり通信用とは互換性がないのか？","ENG":"I guess the parts aren't compatible.","TWN":"果然和通信機器不相容嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"음? 정말로 신호가 다시 잡혔잖아?","JPN":"ん？　本当にまた信号を捉えているじゃないか？","ENG":"Hmm? I'm getting a signal.","TWN":"嗯？真的有重新抓到訊號欸？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"전보다 신호의 강도도 훨씬 선명해! 이거 완전…!","JPN":"前より信号の強度もはるかに鮮明だ！　これはまさに……！","ENG":"And it's much stronger than before! This is...!","TWN":"而且訊號比以前還強！這簡直…！"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"…흠흠. 수고했다, 지휘관.","JPN":"……おっほん。ご苦労だった、指揮官。","ENG":"Ahem... Great work, Commander.","TWN":"…咳咳，辛苦啦，指揮官。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"솔직히 별로 기대하지 않았지만, 네 의견은 상당히 유용했어.","JPN":"正直あまり期待していなかったが、貴様の意見はかなり役に立った。","ENG":"I wasn't expecting much, but your advice was rather useful.","TWN":"老實說，我原本是不抱什麼希望的，但是你的意見蠻有用。"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이만 돌아가지. 언제 다시 침식체가 나타날지 모르니…","JPN":"これくらいにして帰ろう。いつまた侵食体が現れるかわからないから……","ENG":"Let's head back for now. We don't know when the C.O.s will crawl back here again...","TWN":"回去吧，侵蝕體不知道什麼時候會再冒出來…"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"지휘관…?","JPN":"指揮官……？","ENG":"Commander...?","TWN":"指揮官…？"},"stage":{"bg":"PROLOGUE_04","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"뭐, 뭐야! 왜 갑자기 쓰러지는 건데?!","JPN":"な、何だ！　なんでいきなり倒れるんだ！？","ENG":"W-what?! What's wrong?! Why did you suddenly faint?!","TWN":"怎…怎麼搞的！怎麼會突然暈倒？！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"정신 차려!","JPN":"しっかりしろ！","ENG":"Wake up!","TWN":"振作一點！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIVIEN_OPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"VIVIEN_OPR_NULL_NULL","text":{"KOREA":"이봐……!","JPN":"おい……！","ENG":"Hey...!","TWN":"喂……！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};